const files = $json.files || [];
if (!files.length) throw new Error('Nenhum arquivo encontrado');
return [{ json: files[0] }];

function excelSerialToDate(serialNumber) {
  const excelEpoch = new Date(Date.UTC(1899, 11, 30));
  return new Date(excelEpoch.getTime() + Number(serialNumber) * 86400000);
}

function parseDate(value) {
  if (!value || value === '') return null;
  if (value instanceof Date && !isNaN(value)) return value;
  if (typeof value === 'number') {
    const date = excelSerialToDate(value);
    return isNaN(date) ? null : date;
  }
  const str = String(value).trim();
  const ddmmyyyy = str.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (ddmmyyyy) {
    const [_, day, month, year] = ddmmyyyy;
    const date = new Date(Date.UTC(Number(year), Number(month) - 1, Number(day)));
    return isNaN(date) ? null : date;
  }
  const isoDate = new Date(str);
  return isNaN(isoDate) ? null : isoDate;
}

function formatDateISO(date) {
  const year = date.getUTCFullYear();
  const month = String(date.getUTCMonth() + 1).padStart(2, '0');
  const day = String(date.getUTCDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

function normalize(value) {
  if (value === null || value === undefined) return null;
  const str = String(value).trim();
  return str === '' ? null : str;
}

function getField(row, ...fieldNames) {
  for (const fieldName of fieldNames) {
    if (row[fieldName] !== undefined && row[fieldName] !== null) {
      return row[fieldName];
    }
  }
  return null;
}

const items = $input.all();
if (!items.length) return [];

const processedRows = [];

for (const item of items) {
  const row = item.json || {};

  const chapa = normalize(getField(row, 'MAT', 'MATRICULA', 'Matrícula', 'matricula', 'CHAPA', 'chapa'));
  const nome = normalize(getField(row, 'NOME', 'Nome', 'nome'));
  if (!chapa || !nome) continue;

  const funcao = normalize(getField(row, 'FUNÇÃO RM ATUALIZADA', 'FUNCAO RM ATUALIZADA', 'FUNÇÃO', 'FUNCAO', 'funcao'));
  const status = normalize(getField(row, 'STATUS', 'Status', 'status'));
  const area = normalize(getField(row, 'AREA DE NEGOCIO', 'ÁREA DE NEGÓCIO', 'AREA', 'area'));
  const cid = normalize(getField(row, 'CIP DE LIBERAÇÃO', 'CIP DE LIBERACAO', 'CID', 'cid'));
  const rh = normalize(getField(row, 'RH', 'rh'));
  const saude = normalize(getField(row, 'SAÚDE', 'SAUDE', 'saude'));
  const seguranca = normalize(getField(row, 'SEGURANÇA', 'SEGURANCA', 'seguranca'));
  const grd = normalize(getField(row, 'GRD', 'grd'));
  const obs_grd = normalize(getField(row, 'OBSERVAÇÃO GRD', 'OBSERVACAO GRD', 'OBS GRD', 'obs_grd'));

  const dataAcessoRaw = normalize(getField(row, 'DATA DE ACESSO AO PROJETO', 'DATA ACESSO PROJETO', 'data_acesso'));
  const dataAdmissaoRaw = normalize(getField(row, 'DATA ADMISSÃO', 'DATA ADMISSAO', 'DATA DE ADMISSÃO', 'data_admissao'));
  const liberacaoRaw = normalize(getField(row, 'DATA DE LIBERAÇÃO E-COORDINA', 'DATA DE LIBERACAO E-COORDINA', 'liberacao_ecoordin'));

  const dataAcessoDate = parseDate(dataAcessoRaw);
  const dataAdmissaoDate = parseDate(dataAdmissaoRaw);
  const liberacaoDate = parseDate(liberacaoRaw);

  const rowData = {
    chapa: String(chapa),
    nome: String(nome),
    funcao,
    status,
    area,
    cid,
    rh,
    saude,
    seguranca,
    grd,
    obs_grd,
    data_acesso_projeto: dataAcessoDate ? formatDateISO(dataAcessoDate) : null,
    data_admissao: dataAdmissaoDate ? formatDateISO(dataAdmissaoDate) : null,
    liberacao_ecoordin: liberacaoDate ? formatDateISO(liberacaoDate) : null
  };

  processedRows.push({ json: rowData });
}

return processedRows;
